    for bit_count, lmul in all_float_bitcounts_lmuls():
        scalar_type = "float"
        vector_type = f"vfloat{bit_count}{lmul.lower()}_t"
        header.append(f"template<> struct RvvTypeTraits<{scalar_type}, Lmul::{lmul}> {{ using type = {vector_type}; }};")

