template<typename T, Lmul lmul> MaskType<T, lmul> Vmfne(RvvType<T, lmul> vs2, RvvType<T, lmul> vs1, size_t vl) { return FloatComparisonOpTraits<T, lmul>::vmfne_vv(vs2, vs1, vl); }
